@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (_loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (_error is not null)
{
    <div class="alert alert-danger">@_error</div>
}
else
{
    <!-- Stats bar -->
    <div class="row g-2 mb-3">
        <div class="col"><div class="card text-center p-2"><strong>@_allTasks.Count</strong><br /><small class="text-muted">Total</small></div></div>
        @foreach (var col in _columns)
        {
            <div class="col">
                <div class="card text-center p-2">
                    <strong>@TasksInColumn(col).Count</strong><br />
                    <small class="text-muted">@col</small>
                </div>
            </div>
        }
        <div class="col">
            <div class="card text-center p-2 border-danger">
                <strong class="text-danger">@_allTasks.Count(t => t.DueDate.Date < DateTime.Today)</strong><br />
                <small class="text-muted">Overdue</small>
            </div>
        </div>
    </div>

    <!-- Search -->
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title…"
               @bind="_searchTerm" @bind:event="oninput" />
    </div>

    <!-- Columns -->
    <div class="row g-3">
        @for (var i = 0; i < _columns.Length; i++)
        {
            var colIndex = i;
            var colName = _columns[colIndex];
            var tasks = FilteredTasksInColumn(colName);

            <div class="col-md-4">
                <div class="card">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <span class="fw-bold">@colName</span>
                        <span class="badge bg-secondary">@tasks.Count</span>
                    </div>
                    <div class="card-body p-2" style="min-height:200px;">
                        @foreach (var task in tasks)
                        {
                            <div class="card mb-2">
                                <div class="card-body p-2">
                                    <h6 class="card-title mb-1">@task.Title</h6>
                                    <p class="mb-1 text-muted small">@task.Assignee</p>
                                    <div class="d-flex justify-content-between align-items-center mb-1">
                                        <span class="badge @PriorityClass(task.Priority)">@task.Priority</span>
                                        <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
                                    </div>
                                    <div class="d-flex gap-1">
                                        @if (colIndex > 0)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    disabled="@_processing"
                                                    @onclick="() => MoveTaskAsync(task.Id, _columns[colIndex - 1])">
                                                ← Move Left
                                            </button>
                                        }
                                        @if (colIndex < _columns.Length - 1)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    disabled="@_processing"
                                                    @onclick="() => MoveTaskAsync(task.Id, _columns[colIndex + 1])">
                                                Move Right →
                                            </button>
                                        }
                                    </div>
                                </div>
                            </div>
                        }

                        @if (_addingToColumn == colName)
                        {
                            <div class="card border-primary mb-2">
                                <div class="card-body p-2">
                                    <input type="text" class="form-control form-control-sm mb-1"
                                           placeholder="Title" @bind="_newTitle" />
                                    <input type="text" class="form-control form-control-sm mb-1"
                                           placeholder="Assignee" @bind="_newAssignee" />
                                    <select class="form-select form-select-sm mb-1" @bind="_newPriority">
                                        <option value="High">High</option>
                                        <option value="Medium">Medium</option>
                                        <option value="Low">Low</option>
                                    </select>
                                    <input type="date" class="form-control form-control-sm mb-1"
                                           @bind="_newDueDate" />
                                    <div class="d-flex gap-1">
                                        <button class="btn btn-primary btn-sm"
                                                disabled="@_processing"
                                                @onclick="() => SaveNewTaskAsync(colName)">Save</button>
                                        <button class="btn btn-outline-secondary btn-sm"
                                                @onclick="CancelAdd">Cancel</button>
                                    </div>
                                </div>
                            </div>
                        }
                        else
                        {
                            <button class="btn btn-outline-primary btn-sm w-100"
                                    @onclick="() => StartAdd(colName)">+ Add Task</button>
                        }
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private static readonly string[] _columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> _allTasks = new();
    private bool _loading = true;
    private string? _error;
    private string _searchTerm = string.Empty;
    private bool _processing;

    // Add-task form state
    private string? _addingToColumn;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today.AddDays(7);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private List<TaskItem> TasksInColumn(string status)
        => _allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> FilteredTasksInColumn(string status)
        => _allTasks
            .Where(t => t.Status == status &&
                        (string.IsNullOrWhiteSpace(_searchTerm) ||
                         t.Title.Contains(_searchTerm, StringComparison.OrdinalIgnoreCase)))
            .ToList();

    private static string PriorityClass(string priority) => priority switch
    {
        "High"   => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low"    => "bg-success",
        _        => "bg-secondary"
    };

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        _processing = true;
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = _allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                _allTasks[idx] = _allTasks[idx] with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            _error = $"Failed to move task: {ex.Message}";
        }
        finally
        {
            _processing = false;
        }
    }

    private void StartAdd(string column)
    {
        _addingToColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd() => _addingToColumn = null;

    private async Task SaveNewTaskAsync(string column)
    {
        if (string.IsNullOrWhiteSpace(_newTitle))
            return;

        _processing = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(_newTitle.Trim(), _newAssignee.Trim(), _newPriority, _newDueDate);
            // If the service doesn't set the status to the target column, adjust it
            if (created.Status != column)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, column);
                created = created with { Status = column };
            }
            _allTasks.Add(created);
            _addingToColumn = null;
        }
        catch (Exception ex)
        {
            _error = $"Failed to create task: {ex.Message}";
        }
        finally
        {
            _processing = false;
        }
    }
}

