@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (_loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (_error is not null)
{
    <div class="alert alert-danger">@_error</div>
}
else
{
    <!-- Stats bar -->
    <div class="row g-2 mb-3">
        <div class="col"><div class="card text-center p-2"><strong>@_allTasks.Count</strong><br /><small class="text-muted">Total</small></div></div>
        @foreach (var col in _columns)
        {
            <div class="col">
                <div class="card text-center p-2">
                    <strong>@TasksInColumn(col).Count</strong><br />
                    <small class="text-muted">@col</small>
                </div>
            </div>
        }
        <div class="col">
            <div class="card text-center p-2 border-danger">
                <strong class="text-danger">@_allTasks.Count(t => t.DueDate.Date < DateTime.Today)</strong><br />
                <small class="text-muted">Overdue</small>
            </div>
        </div>
    </div>

    <!-- Search -->
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title…"
               @bind="_searchTerm" @bind:event="oninput" />
    </div>

    <!-- Columns -->
    <div class="row g-3">
        @for (var i = 0; i < _columns.Length; i++)
        {
            var colIndex = i;
            var colName = _columns[colIndex];
            var tasks = FilteredTasksInColumn(colName);

            <div class="col-md-4">
                <div class="card">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <span class="fw-bold">@colName</span>
                        <span class="badge bg-secondary">@tasks.Count</span>
                    </div>
                    <div class="card-body p-2" style="min-height:200px;">
                        @foreach (var task in tasks)
                        {
                            <div class="card mb-2">
                                <div class="card-body p-2">
                                    <h6 class="card-title mb-1">@task.Title</h6>
                                    <p class="mb-1 text-muted small">@task.Assignee</p>
                                    <div class="d-flex justify-content-between align-items-center mb-1">
                                        <span class="badge @PriorityClass(task.Priority)">@task.Priority</span>
                                        <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
                                    </div>
                                    <div class="d-flex gap-1">
                                        @if (colIndex > 0)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    disabled="@_processing"
                                                    @onclick="() => MoveTaskAsync(task.Id, _columns[colIndex - 1])">
                                                ← Move Left
                                            </button>
                                        }
                                        @if (colIndex < _columns.Length - 1)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    disabled="@_processing"
                                                    @onclick="() => MoveTaskAsync(task.Id, _columns[colIndex + 1])">
                                                Move Right →
                                            </button>
                                        }
                                    </div>
                                </div>
                            </div>
                        }

