+                                                    @onclick="() => MoveTaskAsync(task.Id, _columns[colIndex + 1])">
+                                                Move Right →
+                                            </button>
+                                        }
+                                    </div>
+                                </div>
+                            </div>
+                        }
+
+                        @if (_addingToColumn == colName)
+                        {
+                            <div class="card border-primary mb-2">
+                                <div class="card-body p-2">
+                                    <input type="text" class="form-control form-control-sm mb-1"
+                                           placeholder="Title" @bind="_newTitle" />
+                                    <input type="text" class="form-control form-control-sm mb-1"
+                                           placeholder="Assignee" @bind="_newAssignee" />
+                                    <select class="form-select form-select-sm mb-1" @bind="_newPriority">
+                                        <option value="High">High</option>
+                                        <option value="Medium">Medium</option>
+                                        <option value="Low">Low</option>
+                                    </select>
+                                    <input type="date" class="form-control form-control-sm mb-1"
+                                           @bind="_newDueDate" />
+                                    <div class="d-flex gap-1">
+                                        <button class="btn btn-primary btn-sm"
+                                                disabled="@_processing"
+                                                @onclick="() => SaveNewTaskAsync(colName)">Save</button>
+                                        <button class="btn btn-outline-secondary btn-sm"
+                                                @onclick="CancelAdd">Cancel</button>
+                                    </div>
+                                </div>
+                            </div>
+                        }
+                        else
+                        {
+                            <button class="btn btn-outline-primary btn-sm w-100"
+                                    @onclick="() => StartAdd(colName)">+ Add Task</button>
+                        }
+                    </div>
+                </div>
+            </div>
+        }
+    </div>
+}
+
+@code {
+    private static readonly string[] _columns = ["To Do", "In Progress", "Done"];
+
+    private List<TaskItem> _allTasks = new();
+    private bool _loading = true;
+    private string? _error;
+    private string _searchTerm = string.Empty;
+    private bool _processing;
+
+    // Add-task form state
+    private string? _addingToColumn;
+    private string _newTitle = string.Empty;
+    private string _newAssignee = string.Empty;
+    private string _newPriority = "Medium";
+    private DateTime _newDueDate = DateTime.Today.AddDays(7);
+
+    protected override async Task OnInitializedAsync()
+    {
+        try
+        {
+            _allTasks = await TaskService.GetAllTasksAsync();
+        }
+        catch (Exception ex)
+        {
+            _error = $"Failed to load tasks: {ex.Message}";
+        }
+        finally
+        {
+            _loading = false;
+        }
+    }
+
+    private List<TaskItem> TasksInColumn(string status)
+        => _allTasks.Where(t => t.Status == status).ToList();
+
+    private List<TaskItem> FilteredTasksInColumn(string status)
+        => _allTasks
+            .Where(t => t.Status == status &&
+                        (string.IsNullOrWhiteSpace(_searchTerm) ||
+                         t.Title.Contains(_searchTerm, StringComparison.OrdinalIgnoreCase)))
+            .ToList();
+
+    private static string PriorityClass(string priority) => priority switch
+    {
+        "High"   => "bg-danger",
+        "Medium" => "bg-warning text-dark",
+        "Low"    => "bg-success",
+        _        => "bg-secondary"
+    };
+
+    private async Task MoveTaskAsync(int taskId, string newStatus)
+    {
+        _processing = true;
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
+            var idx = _allTasks.FindIndex(t => t.Id == taskId);
+            if (idx >= 0)
+            {
+                _allTasks[idx] = _allTasks[idx] with { Status = newStatus };
+            }
+        }
+        catch (Exception ex)
+        {
+            _error = $"Failed to move task: {ex.Message}";
+        }
+        finally
+        {
+            _processing = false;
+        }
+    }
+
+    private void StartAdd(string column)
+    {
+        _addingToColumn = column;
+        _newTitle = string.Empty;
+        _newAssignee = string.Empty;
+        _newPriority = "Medium";
+        _newDueDate = DateTime.Today.AddDays(7);
+    }
+
+    private void CancelAdd() => _addingToColumn = null;
+
+    private async Task SaveNewTaskAsync(string column)
+    {
+        if (string.IsNullOrWhiteSpace(_newTitle))
+            return;
+
+        _processing = true;
+        try
+        {
+            var created = await TaskService.CreateTaskAsync(_newTitle.Trim(), _newAssignee.Trim(), _newPriority, _newDueDate);
+            // If the service doesn't set the status to the target column, adjust it
+            if (created.Status != column)
+            {
+                await TaskService.UpdateTaskStatusAsync(created.Id, column);
+                created = created with { Status = column };
+            }
+            _allTasks.Add(created);
+            _addingToColumn = null;
+        }
+        catch (Exception ex)
+        {
+            _error = $"Failed to create task: {ex.Message}";
+        }
+        finally
+        {
+            _processing = false;
+        }
+    }
+}
+

